// TODO: 读取 data/autoreply-state.json
// 若 enabled=false 则抛错或打标后结束
return items;

// 可直接复用 n8n/snippets/classifyRisk.js
const text = String($json.send_message || '');
const high = ['退款','投诉','售后','举报','假货','骗子','微信','QQ','支付宝','银行卡','线下','转账','私聊','加我'];
const low = ['还在吗','在吗','包邮吗','今天能发吗','能便宜吗','最低多少','小刀'];
let risk = 'medium';
let reason = 'default_medium';
const highHit = high.find((k) => text.includes(k));
if (highHit) { risk = 'high'; reason = `hit_high_keyword:${highHit}`; }
else {
  const lowHit = low.find((k) => text.includes(k));
  if (lowHit) { risk = 'low'; reason = `hit_low_keyword:${lowHit}`; }
}
return [{ json: { ...$json, risk, risk_reason: reason } }];

// 可直接复用 n8n/snippets/lowRiskReplies.js
const text = String($json.send_message || '').trim();
let rule_reply = '';
if (/还在吗|在吗/.test(text)) rule_reply = '在的，喜欢可拍';
else if (/包邮吗/.test(text)) rule_reply = '默认不包，合适可以小刀';
else if (/今天能发吗/.test(text)) rule_reply = '今天拍下可以尽快发';
else if (/能便宜吗|小刀/.test(text)) rule_reply = '可以小刀，你出个合适价';
else if (/最低多少/.test(text)) rule_reply = '价格比较实，合适可拍';
return [{ json: { ...$json, rule_reply } }];

// 可直接复用 n8n/snippets/sanitizeReply.js
const maxReplyChars = Number($json.max_reply_chars || 80);
const blocked = /(微信|QQ|支付宝|银行卡|线下|转账|私聊|加我)/i;
let text = String($json.reply || $json.rule_reply || '').replace(/<think>[\s\S]*?<\/think>/gi, ' ');
text = text.replace(/```(?:thinking|reasoning|analysis)[\s\S]*?```/gi, ' ');
const markers = ['最终回复：','最终回复:','买家可见回复：','买家可见回复:','回复：','回复:'];
for (const marker of markers) {
  const idx = text.lastIndexOf(marker);
  if (idx >= 0) text = text.slice(idx + marker.length);
}
text = text.split(/\r?\n/)
  .map((line) => line.replace(/^\s*(?:[-*+]|#{1,6}|>|\d+[.)])\s*/, '').trim())
  .filter((line) => line && !/^(思考|分析|推理|判断|策略|步骤|理由|reasoning|analysis)/i.test(line))
  .join(' ')
  .replace(/\s+/g, ' ')
  .trim();
if (blocked.test(text)) text = '平台内沟通就行，合适可拍';
text = text.slice(0, maxReplyChars);
return [{ json: { ...$json, sanitized_reply: text } }];

let final_reply = String($json.sanitized_reply || '').trim();
if (/(微信|QQ|支付宝|银行卡|线下|转账|私聊|加我)/i.test(final_reply)) {
  final_reply = '平台内沟通就行，合适可拍';
}
return [{ json: { ...$json, final_reply } }];
